{
  "grammar": [
    {
      "pattern": "Subject + 可以幫我 + Verb + Object + 嗎？",
      "structure": ["Subject", "可以幫我", "Verb", "Object", "嗎"],
      "explanation_en": "Use this pattern to politely ask someone to do something for you. It's a common and polite way to request help in Taiwan.",
      "title": "Polite Request for Help",
      "meaning": "Can you help me...?",
      "when_to_use": ["When you need someone to perform an action for you", "In service situations like asking a store clerk or a friend"],
      "when_not_to_use": ["When the request is very urgent or formal", "When speaking to a superior in a very formal context"],
      "pragmatic_notes": "In Taiwan, adding 嗎 at the end makes the request softer and more polite. It's commonly used in daily interactions.",
      "word_order_notes": "The verb directly follows 幫我, and the object comes after the verb.",
      "english_contrast": "In English, we say 'Can you help me + verb?' but in Chinese, the structure is 'Can help me + verb + object?'",
      "korean_contrast": "In Korean, you might say '도와주세요' but in Chinese, you specify the action after 幫我.",
      "negative_examples": [
        {
          "text": "你幫我找手機嗎？",
          "error": "Missing 可以 before 幫我 to make it a polite request."
        }
      ],
      "incorrect_examples": [
        {
          "text": "幫我你找手機嗎？",
          "error": "Word order is wrong; 你 should come before 可以幫我."
        }
      ],
      "transformation_drills": ["Change '你幫我找手機嗎？' to '你可以幫我找手機嗎？'"],
      "production_drills": ["Ask a friend to help you find your phone."],
      "common_error_patterns": ["Omitting 可以", "Placing 你 after 幫我"],
      "repair_feedback": {
        "word_order": "Remember: Subject + 可以幫我 + Verb + Object + 嗎",
        "politeness": "Adding 可以 makes the request more polite.",
        "vocabulary": "Use 幫我 for 'help me'."
      }
    },
    {
      "pattern": "Subject + 需要 + Verb + Object",
      "structure": ["Subject", "需要", "Verb", "Object"],
      "explanation_en": "Use this pattern to express a need or necessity. It's straightforward and commonly used in Taiwan.",
      "title": "Expressing Need",
      "meaning": "I need to...",
      "when_to_use": ["When stating a necessity", "In both formal and informal contexts"],
      "when_not_to_use": ["When making a polite request (use 可以幫我 instead)", "When expressing desire (use 想 instead)"],
      "pragmatic_notes": "In Taiwan, 需要 is neutral and can be used in many situations, from daily needs to formal requirements.",
      "word_order_notes": "需要 is followed directly by a verb or a noun phrase.",
      "english_contrast": "In English, 'need' can be followed by a noun or verb, same as Chinese.",
      "korean_contrast": "In Korean, '필요하다' is used similarly, but Chinese uses 需要 directly before the action.",
      "negative_examples": [
        {
          "text": "我需要幫你找手機。",
          "error": "This means 'I need to help you find the phone,' not 'I need you to help me.'"
        }
      ],
      "incorrect_examples": [
        {
          "text": "我需要你幫我找手機。",
          "error": "This is actually correct, but if you want to request help, use 可以幫我 instead."
        }
      ],
      "transformation_drills": ["Change '我需要找手機' to '我需要你幫我找手機'"],
      "production_drills": ["Say you need to find your phone."],
      "common_error_patterns": ["Confusing 需要 with 想要", "Using 需要 for polite requests"],
      "repair_feedback": {
        "word_order": "Subject + 需要 + Verb/Object",
        "politeness": "For requests, use 可以幫我 instead of 需要.",
        "vocabulary": "需要 is for needs, not polite requests."
      }
    },
    {
      "pattern": "Subject + 可以 + Verb + Object + 嗎？ / Subject + 必須 + Verb + Object",
      "structure": ["Subject", "可以/必須", "Verb", "Object", "嗎"],
      "explanation_en": "Use 可以 to ask for permission or possibility, and 必須 to express obligation. In Taiwan, 可以 is softer and more polite for requests.",
      "title": "Permission vs. Obligation",
      "meaning": "Can I...? / I must...",
      "when_to_use": ["Use 可以 to ask if something is allowed", "Use 必須 to state a necessity or rule"],
      "when_not_to_use": ["Do not use 必須 for polite requests", "Do not use 可以 for strong obligations"],
      "pragmatic_notes": "In Taiwan, 可以 is very common in service contexts, e.g., '我可以試穿嗎？' 必須 is more formal and direct.",
      "word_order_notes": "可以 and 必須 come before the verb, and the object after the verb.",
      "english_contrast": "In English, 'can' and 'must' are similar, but Chinese uses 嗎 for questions with 可以.",
      "korean_contrast": "In Korean, '~해도 돼요?' is similar to 可以, and '~해야 해요' is similar to 必須.",
      "negative_examples": [
        {
          "text": "我必須幫你找手機嗎？",
          "error": "This sounds like 'Must I help you find the phone?' which is too strong for a request."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我可以必須找手機。",
          "error": "Cannot use 可以 and 必須 together; choose one."
        }
      ],
      "transformation_drills": ["Change '我必須找手機' to '我可以找手機嗎？'"],
      "production_drills": ["Ask if you can use the phone.", "Say you must find your phone."],
      "common_error_patterns": ["Mixing 可以 and 必須", "Using 必須 for polite requests"],
      "repair_feedback": {
        "word_order": "可以/必須 + Verb + Object",
        "politeness": "Use 可以 for polite requests, 必須 for obligations.",
        "vocabulary": "Choose the correct modal verb based on context."
      }
    }
  ]
}
